export type NumberString = `${number}`;
export type PercentageString = `${number}%`;
export type PixelLengthString = `${number}px`;
export type ViewportHeightLengthString = `${number}vh` | `${number}dvh` | `${number}svh` | `${number}lvh`;
export type ViewportWidthLengthString = `${number}vw` | `${number}dvw` | `${number}svw` | `${number}lvw`;
export type ViewportLengthString = ViewportHeightLengthString | ViewportWidthLengthString;
export type NumberValue = number | NumberString;
export type AbsoluteLengthValue = NumberValue | PixelLengthString;
export type LengthValue = AbsoluteLengthValue | PercentageString | ViewportLengthString;
export type NumberOrPercentageValue = NumberValue | PercentageString;
export declare function isNumberString(value: unknown): value is NumberString;
export declare function isPercentageString(value: unknown): value is PercentageString;
export declare function isPixelLengthString(value: unknown): value is PixelLengthString;
export declare function isViewportLengthString(value: unknown): value is ViewportLengthString;
export declare function isViewportHeightLength(value: unknown): value is ViewportHeightLengthString;
export declare function isViewportWidthLength(value: unknown): value is ViewportWidthLengthString;
export declare function parseAbsoluteNumber(value: number | string, getRelativeValue?: () => number, viewportWidth?: number, viewportHeight?: number): number;
export declare function parseNumberValue(value: NumberValue): number;
export declare function parseAbsoluteLengthValue(value: AbsoluteLengthValue): number;
export declare function convertYogaPoint(input: LengthValue | undefined, viewportWidth: number, viewportHeight: number): PercentageString | number | undefined;
